import threading
from functools import wraps

def debounce(wait: float):
    def decorator(fn):
        timer = None
        @wraps(fn)
        def debounced(*args, **kwargs):
            nonlocal timer
            if timer is not None:
                timer.cancel()
            timer = threading.Timer(wait, fn, args=args, kwargs=kwargs)
            timer.start()
        return debounced
    return decorator
